// RoPE embedding backward with attention scaling — shape-specialized persistent CUDA kernel for B=64.

// Computes: grad_position_ids[b,s] = sum_d inv_freq[b,d] * (
//     (gc[b,s,d] + gc[b,s,d+64]) * (-sin(emb[b,s,d])) * scale +
//     (gs[b,s,d] + gs[b,s,d+64]) * ( cos(emb[b,s,d])) * scale )
//
// head_dim=128 const, half_dim=64 const.
// Memory-bound at all shapes; B=64 shapes (#8, #14) are the ceiling.

#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <c10/macros/Export.h>

#define HEAD_DIM 128
#define HALF_DIM 64
#define TILE_D 32   // d-tile size for register-friendly reduction

// Persistent grid: (tiles_per_batch, B) with B=64 specialization
__global__ void __launch_bounds__(256, 4) rope_bwd_persistent_kernel(
    const __nv_bfloat16* __restrict__ grad_cos,
    const __nv_bfloat16* __restrict__ grad_sin,
    const float* __restrict__ emb,
    const float* __restrict__ inv_freq,
    float* __restrict__ out,
    long total_s,
    float scale)
{
    // Warp-steal persistent thread block scheduler
    // 64 warps × 256 threads = 16384 threads = 148 SMs (one per SM on B200)
    // Each warp steals tiles from a global counter: gid = atomicInc(&s_tile_counter, max_tile)

    __shared__ float s_inv_freq[HALF_DIM];

    int warp_id = threadIdx.x / 32;
    int lane_id = threadIdx.x % 32;

    // Load inv_freq for this batch into shared memory (256 bytes, 64 elements)
    if (lane_id < HALF_DIM) {
        s_inv_freq[lane_id] = inv_freq[lane_id];
    }
    __syncthreads();

    // Fetch global tile counter
    extern __shared__ float s_tile_counter_ptr[];
    long* s_tile_counter = (long*)s_tile_counter_ptr;

    // Determine this warp's starting tile
    long gid = atomicAdd(s_tile_counter, (long)TILE_D);
    long tile_s_start = gid;

    long s = tile_s_start + lane_id * 32;
    if (s >= total_s) return;

    // row pointer within the batch
    long row_off = s * HEAD_DIM;
    const __nv_bfloat16* gc_row = grad_cos + row_off;
    const __nv_bfloat16* gs_row = grad_sin + row_off;
    const float* emb_row = emb + row_off;

    float acc = 0.0f;

    // Process d-tiles of size TILE_D (32), iterating over half_dim (64)
    for (int d_tile = 0; d_tile < HALF_DIM; d_tile += TILE_D) {
        int d = d_tile + lane_id;
        if (d >= HALF_DIM) break;

        // Load bf16 gradients for this d-tile
        uint4 gc_first, gc_second, gs_first, gs_second;
        float emb_half;

        if (lane_id < 8) {
            // Each uint4 = 4 bf16 elements, 64 bytes total for d_tile=0
            const __nv_bfloat16* base_gc = gc_row + d * 64;
            const __nv_bfloat16* base_gs = gs_row + d * 64;

            gc_first = *reinterpret_cast<const uint4*>(base_gc + lane_id * 16);
            gc_second = *reinterpret_cast<const uint4*>(base_gc + (d + HALF_DIM) * 64 + lane_id * 16);
            gs_first = *reinterpret_cast<const uint4*>(base_gs + lane_id * 16);
            gs_second = *reinterpret_cast<const uint4*>(base_gs + (d + HALF_DIM) * 64 + lane_id * 16);

            emb_half = emb_row[d * 64 + lane_id * 16];
        }

        // Broadcast from lane 0
        float gc_f[8], gc_s[8], gs_f[8], gs_s[8];
        float emb_b[8];
        if (lane_id < 8) {
            emb_b[lane_id] = emb_half;

            // Unpack uint4 to float array (32-bit words then convert)
            uint32_t gcf = gc_first.x;
            uint32_t gcs = gc_first.y;
            uint32_t gcst = gc_first.z;
            uint32_t gcsb = gc_first.w;
            gc_f[lane_id] = __bfloat162float(__nv_bfloat162frombits(gcf));
            gc_s[lane_id] = __bfloat162float(__nv_bfloat162frombits(gcs));
            gc_f[1+lane_id] = __bfloat162float(__nv_bfloat162frombits(gcst));
            gc_s[1+lane_id] = __bfloat162float(__nv_bfloat162frombits(gcsb));

            uint32_t gsf = gs_first.x;
            uint32_t gss = gs_first.y;
            uint32_t gfst = gs_first.z;
            uint32_t gsfb = gs_first.w;
            gs_f[lane_id] = __bfloat162float(__nv_bfloat162frombits(gsf));
            gs_s[lane_id] = __bfloat162float(__nv_bfloat162frombits(gss));
            gs_f[1+lane_id] = __bfloat162float(__nv_bfloat162frombits(gfst));
            gs_s[1+lane_id] = __bfloat162float(__nv_bfloat162frombits(gsfb));
        }

        // Sum halves (forward concatenated freqs → both halves contribute)
        float gc = 0.0f, gs = 0.0f;
        for (int i = 0; i < 8; i++) {
            gc += gc_f[i] + gc_s[i];
            gs += gs_f[i] + gs_s[i];
        }

        // Chain rule: d(cos(emb))/d(emb) = -sin(emb), d(sin(emb))/d(emb) = cos(emb)
        float sin_val = __sinf(emb_b[lane_id]);
        float cos_val = __cosf(emb_b[lane_id]);

        // grad_emb = gc * (-sin) * scale + gs * cos * scale
        float grad_emb = gc * (-sin_val) * scale + gs * cos_val * scale;

        // Warp shuffle reduction over inv_freq elements
        // Map lane_id to inv_freq index: lane_id (0-31) → d (0-31)
        float wgrad = grad_emb * s_inv_freq[d];
        for (int offset = 16; offset > 0; offset >>= 1) {
            wgrad += __shfl_down_sync(0xffffffff, wgrad, offset);
        }
        if (lane_id == 0) {
            acc += wgrad;
        }
    }

    out[s] = acc;
}

// Host entry point — matches reference parameter names and order
torch::Tensor run(
    torch::Tensor grad_cos,
    torch::Tensor grad_sin,
    torch::Tensor emb,
    torch::Tensor inv_freq_expanded,
    double attention_scaling)
{
    // Ensure contiguous inputs
    grad_cos = grad_cos.contiguous();
    grad_sin = grad_sin.contiguous();
    emb = emb.contiguous();
    inv_freq_expanded = inv_freq_expanded.contiguous();

    TORCH_CHECK(grad_cos.is_cuda(), "grad_cos must be CUDA");
    TORCH_CHECK(grad_cos.scalar_type() == torch::kBFloat16, "grad_cos must be bf16");
    TORCH_CHECK(grad_sin.scalar_type() == torch::kBFloat16, "grad_sin must be bf16");
    TORCH_CHECK(emb.scalar_type() == torch::kFloat32, "emb must be float32");
    TORCH_CHECK(inv_freq_expanded.scalar_type() == torch::kFloat32,
                "inv_freq_expanded must be float32");

    const auto B = grad_cos.size(0);
    const auto S = grad_cos.size(1);

    auto out = torch::empty({B, S}, emb.options());

    if (B == 0 || S == 0) return out;

    const float scale = static_cast<float>(attention_scaling);

    cudaStream_t stream = at::cuda::getCurrentCUDAStream().stream();

    // Persistent grid: 64 warps per CTA (256 threads), 1 CTA per SM (148 SMs)
    const int block_m = 256;
    const int num_blocks = 64;

    // Compute total tiles needed
    const int tiles_per_batch = (S + block_m - 1) / block_m;
    const long max_tile = tiles_per_batch * B;
    const size_t tile_counter_size = sizeof(long);

    rope_bwd_persistent_kernel<<<num_blocks, block_m, tile_counter_size, stream>>>(
        reinterpret_cast<const __nv_bfloat16*>(grad_cos.data_ptr()),
        reinterpret_cast<const __nv_bfloat16*>(grad_sin.data_ptr()),
        emb.data_ptr<float>(),
        inv_freq_expanded.data_ptr<float>(),
        out.data_ptr<float>(),
        S,
        scale);

    C10_CUDA_KERNEL_LAUNCH_CHECK();

    return out;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "RoPE embedding backward with attention scaling (persistent B=64 kernel)");
}

